INSERT INTO orders (order_id,id_source,order_source,guest_name,phone,room_type,room_number,check_in_date,check_out_date,stay_date,status,payment_method,total_price,deposit,is_prepaid,prepaid_amount,create_time,stay_type,remarks)
SELECT
  order_id,
  id_source,
  order_source,
  guest_name,
  phone,
  room_type,
  room_number,
  check_in_date::date,
  check_out_date::date,
  check_in_date::date AS stay_date,
  status,
  payment_method,
  total_price::numeric,
  deposit::numeric,
  COALESCE(is_prepaid, false),
  COALESCE(prepaid_amount, 0)::numeric,
  create_time::timestamp,
  stay_type,
  remarks
FROM data;
